! Fortran 90 interfaces to Apple Accelerate LAPACK (LP64).
!
! Integer arguments use default integer (4 bytes).
! Binds to the ACCELERATE_NEW_LAPACK symbols via the $NEWLAPACK suffix.
! Function pointer arguments (e.g. SELECT in xGEES) use type(c_funptr).
!
! Usage:
!   use accelerate_lapack_lp64
!   call dgetrf(m, n, a, lda, ipiv, info)

module accelerate_lapack_lp64
  use iso_c_binding, only: c_funptr
  implicit none

  interface

    subroutine chla_transtype(ret_val, ret_value_len, trans) &
      bind(C, name='chla_transtype$NEWLAPACK')
      character, intent(inout) :: ret_val
      integer, value, intent(in) :: ret_value_len
      integer, intent(in) :: trans
    end subroutine chla_transtype

    integer function sisnan(sin) &
      bind(C, name='sisnan$NEWLAPACK')
